"use client";

import { useState } from "react";
import { useForm } from "react-hook-form";
import { zodResolver } from "@hookform/resolvers/zod";
import { signIn } from "next-auth/react";
import { useRouter, useSearchParams } from "next/navigation";
import { Eye, EyeOff, Loader2, Mail, Lock, ArrowRight, ShieldCheck } from "lucide-react";
import { toast } from "sonner";
import { Input } from "@/components/ui/input";
import { Label } from "@/components/ui/label";
import { loginSchema, type LoginInput } from "@/lib/validations/auth";

export default function HrLoginPage() {
  const router = useRouter();
  const searchParams = useSearchParams();
  const callbackUrl = searchParams.get("callbackUrl") || "/hr/dashboard";
  const [showPassword, setShowPassword] = useState(false);
  const [isLoading, setIsLoading] = useState(false);

  const { register, handleSubmit, formState: { errors } } = useForm<LoginInput>({
    resolver: zodResolver(loginSchema),
    defaultValues: { email: "", password: "" },
  });

  const onSubmit = async (data: LoginInput) => {
    setIsLoading(true);
    try {
      const result = await signIn("credentials", {
        email: data.email.toLowerCase(),
        password: data.password,
        redirect: false,
      });

      if (result?.error) {
        const errorMessages: Record<string, string> = {
          "No account found with this email": "No account found with this email address.",
          "Incorrect password": "Incorrect password. Please try again.",
          "Please verify your email before logging in": "Please verify your email before logging in.",
          "Your account has been deactivated": "Your account has been deactivated. Please contact admin.",
        };
        toast.error(errorMessages[result.error] ?? "Login failed. Please check your credentials.");
        return;
      }

      if (result?.ok) {
        toast.success("Welcome to HR Portal!");
        router.push(callbackUrl);
        router.refresh();
      }
    } catch {
      toast.error("An unexpected error occurred. Please try again.");
    } finally {
      setIsLoading(false);
    }
  };

  return (
    <div className="min-h-screen bg-background flex">

      {/* Left panel — dark hero */}
      <div
        className="hidden lg:flex lg:w-1/2 flex-col relative overflow-hidden"
        style={{ background: "var(--gradient-hero)" }}
      >
        {/* Grid dots */}
        <div
          className="absolute inset-0 pointer-events-none"
          aria-hidden="true"
          style={{
            backgroundImage: "radial-gradient(rgba(0,212,255,0.12) 1px, transparent 1px)",
            backgroundSize: "30px 30px",
          }}
        />

        {/* Radial glow */}
        <div
          className="absolute inset-0 pointer-events-none"
          style={{ background: "radial-gradient(ellipse 70% 55% at 50% 40%, rgba(0,212,255,0.08) 0%, transparent 70%)" }}
          aria-hidden="true"
        />

        {/* Orbit rings */}
        {[300, 500, 700].map((size, i) => (
          <div
            key={size}
            className="absolute rounded-full border border-primary/20 animate-spin-slow"
            style={{
              width: size, height: size,
              top: "50%", left: "50%",
              marginTop: -size / 2, marginLeft: -size / 2,
              animationDelay: `${i * -4}s`,
              opacity: [0.18, 0.10, 0.06][i],
            }}
            aria-hidden="true"
          />
        ))}

        {/* Content */}
        <div className="relative z-10 flex flex-col h-full px-12 py-12">
          {/* Logo */}
          <div className="flex items-center gap-3 mb-12">
            <div className="flex h-12 w-12 items-center justify-center rounded-2xl border border-white/20 bg-white/15 shadow-[0_0_24px_rgba(0,212,255,0.25)]">
              <ShieldCheck className="h-6 w-6 text-white" />
            </div>
            <div>
              <p className="font-bold text-xl text-white leading-none tracking-wide">NWDI</p>
              <p className="text-xs text-white/50 tracking-[0.2em] uppercase mt-0.5">Health Services</p>
            </div>
          </div>

          {/* Hero copy */}
          <div className="flex-1 flex flex-col justify-center">
            <div className="mb-8">
              <span className="inline-flex items-center gap-2 rounded-full border border-white/20 bg-white/10 px-3.5 py-1 text-xs font-semibold text-white/80 tracking-widest uppercase mb-6">
                <span className="live-dot-green" style={{ width: 6, height: 6 }} />
                HR Staff Portal
              </span>
              <h1 className="text-4xl xl:text-5xl font-bold text-white leading-[1.1] mb-4">
                Hospital<br />
                <span className="text-gradient-primary">Records</span><br />
                Management.
              </h1>
              <p className="text-sm text-white/55 leading-relaxed max-w-xs">
                Securely access and manage all patient records, hospital visits, lab results, vitals, and payment history across all employees.
              </p>
            </div>

            {/* Feature cards */}
            <div className="grid grid-cols-2 gap-3">
              {[
                { icon: "👥", label: "All Patient Records",  color: "border-cyan-400/20 bg-cyan-400/8" },
                { icon: "📋", label: "Visit Management",      color: "border-blue-400/20 bg-blue-400/8" },
                { icon: "🧪", label: "Lab Results Access",    color: "border-purple-400/20 bg-purple-400/8" },
                { icon: "💊", label: "Full Vitals History",   color: "border-pink-400/20 bg-pink-400/8" },
              ].map((f) => (
                <div key={f.label} className={`flex items-center gap-2.5 rounded-xl border px-3 py-2.5 ${f.color}`}>
                  <span className="text-base">{f.icon}</span>
                  <span className="text-xs font-medium text-white/75 leading-tight">{f.label}</span>
                </div>
              ))}
            </div>
          </div>

          <p className="text-[10px] text-white/25 text-center mt-10 tracking-[0.2em] uppercase">
            BAESA Clinical Management System — HR Access
          </p>
        </div>
      </div>

      {/* Right panel — form */}
      <div className="flex lg:w-1/2 flex-1 flex-col bg-background relative overflow-hidden">

        {/* Mobile header */}
        <header className="relative z-10 flex items-center gap-3 px-6 py-5 lg:hidden border-b border-border">
          <div className="flex h-9 w-9 items-center justify-center rounded-xl bg-primary/10 border border-primary/25">
            <ShieldCheck className="h-4 w-4 text-primary" />
          </div>
          <span className="font-bold text-foreground text-sm tracking-wide">NWDI HR Portal</span>
        </header>

        <main className="relative z-10 flex flex-1 items-center justify-center px-12 py-12">
          <div className="w-full max-w-md animate-slide-up space-y-8">

            {/* Header */}
            <div className="space-y-2">
              <div className="flex items-center gap-2 mb-1">
                <div className="flex h-6 w-6 items-center justify-center rounded-lg bg-primary/10 border border-primary/20">
                  <ShieldCheck className="h-3.5 w-3.5 text-primary" />
                </div>
                <span className="text-xs font-semibold text-primary tracking-wider uppercase">HR Staff Access</span>
              </div>
              <h2 className="text-3xl font-bold text-foreground leading-tight tracking-tight">
                Staff sign in
              </h2>
              <p className="text-sm text-muted-foreground leading-relaxed">
                Sign in to access the HR portal and manage all hospital records
              </p>
            </div>

            {/* Form */}
            <form onSubmit={handleSubmit(onSubmit)} className="space-y-5">

              {/* Email */}
              <div className="space-y-2">
                <Label htmlFor="email" className="text-sm font-medium text-foreground">
                  Staff email address
                </Label>
                <div className="relative">
                  <Mail className="absolute left-3.5 top-1/2 -translate-y-1/2 h-4 w-4 text-muted-foreground/50" />
                  <Input
                    id="email"
                    type="email"
                    placeholder="staff@nwdi.com"
                    autoComplete="email"
                    disabled={isLoading}
                    {...register("email")}
                    className={`pl-10 h-11 rounded-xl bg-card border-border text-foreground placeholder:text-muted-foreground/50 ${
                      errors.email
                        ? "border-destructive focus-visible:ring-destructive/20"
                        : "focus-visible:border-primary focus-visible:ring-primary/15"
                    }`}
                  />
                </div>
                {errors.email && (
                  <p className="text-xs text-destructive flex items-center gap-1.5">
                    <span className="w-1.5 h-1.5 rounded-full bg-destructive shrink-0" />
                    {errors.email.message}
                  </p>
                )}
              </div>

              {/* Password */}
              <div className="space-y-2">
                <Label htmlFor="password" className="text-sm font-medium text-foreground">
                  Password
                </Label>
                <div className="relative">
                  <Lock className="absolute left-3.5 top-1/2 -translate-y-1/2 h-4 w-4 text-muted-foreground/50" />
                  <Input
                    id="password"
                    type={showPassword ? "text" : "password"}
                    placeholder="Enter your password"
                    autoComplete="current-password"
                    disabled={isLoading}
                    {...register("password")}
                    className={`pl-10 pr-11 h-11 rounded-xl bg-card border-border text-foreground placeholder:text-muted-foreground/50 ${
                      errors.password
                        ? "border-destructive focus-visible:ring-destructive/20"
                        : "focus-visible:border-primary focus-visible:ring-primary/15"
                    }`}
                  />
                  <button
                    type="button"
                    tabIndex={-1}
                    onClick={() => setShowPassword(!showPassword)}
                    className="absolute right-3.5 top-1/2 -translate-y-1/2 text-muted-foreground/50 hover:text-muted-foreground transition-colors"
                  >
                    {showPassword ? <EyeOff className="h-4 w-4" /> : <Eye className="h-4 w-4" />}
                  </button>
                </div>
                {errors.password && (
                  <p className="text-xs text-destructive flex items-center gap-1.5">
                    <span className="w-1.5 h-1.5 rounded-full bg-destructive shrink-0" />
                    {errors.password.message}
                  </p>
                )}
              </div>

              {/* Submit */}
              <button
                type="submit"
                disabled={isLoading}
                className="w-full h-11 rounded-xl text-sm font-semibold text-white flex items-center justify-center gap-2 transition-all disabled:opacity-60 disabled:cursor-not-allowed mt-1"
                style={{ background: "var(--gradient-primary)" }}
              >
                {isLoading ? (
                  <><Loader2 className="h-4 w-4 animate-spin" />Signing in…</>
                ) : (
                  <>Sign in to HR Portal <ArrowRight className="h-4 w-4" /></>
                )}
              </button>
            </form>

            {/* Trust */}
            <div className="flex items-center justify-center gap-1.5 text-xs text-muted-foreground/50">
              <ShieldCheck className="h-3.5 w-3.5" />
              <span>HR access only · Authorized personnel</span>
            </div>
          </div>
        </main>

        <footer className="relative z-10 px-6 py-5 border-t border-border text-center">
          <p className="text-xs text-muted-foreground">
            &copy; {new Date().getFullYear()} NWDI Health Services. All rights reserved.
          </p>
        </footer>
      </div>
    </div>
  );
}
